// 토픽별 묶기 헬퍼
export function problemsByTopic(io?: ExtIO): Record<string, ExtProblem[]> {
  const out: Record<string, ExtProblem[]> = {}
  for (const p of EXTERNAL_PROBLEMS) {
    if (io && p.io !== io) continue
    ;(out[p.topic] ||= []).push(p)
  }
  return out
}

